def lis(nums):
    """
    Returns the length of the longest strictly increasing subsequence in `nums`.
    Uses an O(n log n) patience sorting algorithm.
    """
    import bisect

    tails = []  # tails[i] = smallest possible tail value of an IS of length i+1
    for x in nums:
        idx = bisect.bisect_left(tails, x)
        if idx == len(tails):
            tails.append(x)
        else:
            tails[idx] = x
    return len(tails)
